  DATA['Lesson01/lesson.json'] = "{\n  \"lessonNumber\": 1,\n  \"title\": \"코딩 입문과 알비 만남\",\n  \"tag\": \"theory\",\n  \"hardware\": \"(이론) Bluetooth 페어링\",\n  \"concept\": \"순차/반복 개념, 앱 설치\",\n  \"intro\": \"본 차시는 ARES 교육과정의 출발점이다. \\\"코딩이란 무엇인가?\\\"라는 근본 질문에서 시작하여, 모바일 블록 코딩 앱 설치 및 블루투스를 통한 로버 알비(Pico W)와의 첫 연결까지를 다룬다. 본격적인 하드웨어 제어 이전에 학습자는 순차(Sequence)와 반복(Loop)이라는 두 가지 핵심 개념을 익히고, 앞으로 만들 작품들을 미리 살펴본다.\",\n  \"missions\": [\n    {\n      \"id\": 1,\n      \"title\": \"코딩이란 무엇인가?\",\n      \"tag\": \"theory\",\n      \"hardware\": \"(이론 수업)\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! 앞으로 내가 코딩으로 명령을 내리면 네가 움직이는 거지?\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 맞아요! 스마트폰 앱으로 저와 연결하면 언제든 명령을 보낼 수 있어요!\"}\n      ],\n      \"goals\": [\n        \"코딩 = 컴퓨터에게 할 일을 순서대로 알려주는 것\",\n        \"순차(Sequence): 정해진 순서대로 실행\",\n        \"반복(Loop): 같은 동작을 여러 번 자동 실행\",\n        \"코딩 환경(앱) 설치 및 소개\"\n      ],\n      \"sampleCode\": \"# 1차시: 코딩 이론 수업\\n# 코딩이란 컴퓨터에게 할 일을 순서대로 알려주는 것!\\n# 이번 시간은 이론 수업입니다 :)\"\n    },\n    {\n      \"id\": 2,\n      \"title\": \"모바일 앱 설치하기\",\n      \"tag\": \"theory\",\n      \"hardware\": \"(이론/설치 활동)\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비, 앱을 어떻게 설치해?\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- QR코드를 스캔하거나 웹 주소로 접속하면 돼요! Wi-Fi가 없어도 파일로 설치할 수 있어요.\"}\n      ],\n      \"goals\": [\n        \"와이파이 없는 환경: 웹 파일 다운로드 후 설치\",\n        \"와이파이 있는 환경: QR코드 또는 웹페이지 접속\",\n        \"Bluetooth로 알비(Pico W)와 연결 테스트\",\n        \"앱 화면 구성 익히기\"\n      ],\n      \"sampleCode\": \"# 앱 설치 및 블루투스 연결\\n# 이 수업은 실습 활동입니다.\\n# 앱을 설치하고 블루투스로 연결해보세요!\"\n    },\n    {\n      \"id\": 3,\n      \"title\": \"블루투스 연결 테스트\",\n      \"tag\": \"theory\",\n      \"hardware\": \"(이론/연결 실습)\",\n      \"story\": [\n        {\"speaker\": \"albi\", \"text\": \"삐릿! 연결이 됐나요? 화면에 CONNECTED라고 뜨면 성공이에요!\"},\n        {\"speaker\": \"ares\", \"text\": \"오! 연결됐어! 이제 코딩으로 알비를 움직일 수 있겠구나!\"}\n      ],\n      \"goals\": [\n        \"스마트폰과 피코 W 블루투스 페어링\",\n        \"앱에서 연결 버튼 눌러 CONNECTED 확인\",\n        \"연결 상태 LED로 확인하기\"\n      ],\n      \"sampleCode\": \"# 연결 확인\\nif bluetooth.connected():\\n    print(\\\"CONNECTED\\\")\\n    led_on(1, 1.0)  # 연결 확인 LED\"\n    },\n    {\n      \"id\": 4,\n      \"title\": \"1분기 탐사 일지 작성\",\n      \"tag\": \"theory\",\n      \"hardware\": \"(이론/예고편)\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! 우리가 앞으로 뭘 만들게 되는 거야?\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿♪ LED로 빛을, 부저로 소리를, 모터로 움직임을 만들어요. 마지막엔 로켓 발사까지!\"}\n      ],\n      \"goals\": [\n        \"1분기 전체 제작 목록 미리보기\",\n        \"탐사 일지 첫 페이지 작성하기\",\n        \"LED·부저·DC모터가 무엇인지 소개\"\n      ],\n      \"sampleCode\": \"# 1분기 예고편!\\n# LED → 부저 → DC모터 순서로 배울 거예요\\nprint(\\\"화성 탐사 대장정 시작!\\\")\"\n    }\n  ],\n  \"summary\": {\n    \"type\": \"summary\",\n    \"title\": \"1차시 요약\",\n    \"text\": \"1차시는 이론 중심 수업이다. 코딩의 본질(순서대로 명령을 전달하는 행위)을 이해하고, 학습 환경(블록 코딩 앱 + Pico W 블루투스 페어링)을 구축하는 것이 핵심이다. 4개 미션 모두 코드 작성은 최소화되어 있으며, 학습자는 앞으로 펼쳐질 12차시 여정의 큰 그림을 그리는 데 집중한다.\"\n  }\n}\n";
  DATA['Lesson02/lesson.json'] = "{\n  \"lessonNumber\": 2,\n  \"title\": \"LED 기초: 알비의 첫 호흡\",\n  \"tag\": \"LED\",\n  \"hardware\": \"LED 1개\",\n  \"concept\": \"디지털 출력 HIGH/LOW, time.sleep\",\n  \"intro\": \"본 차시는 학습자가 처음으로 실제 하드웨어를 코드로 제어하는 단계이다. 가장 단순한 출력 장치인 LED를 통해 HIGH/LOW 두 상태, 시간 지연(time.sleep), 그리고 짧은 반복문을 익힌다. 4개의 미션은 'LED 1개를 한 번 켜기 → 여러 번 깜빡이기 → 속도 조절 → 메인보드 박스 완성'의 흐름으로 이어진다.\",\n  \"missions\": [\n    {\n      \"id\": 1,\n      \"title\": \"LED 점등 테스트\",\n      \"tag\": \"LED\",\n      \"hardware\": \"LED 1개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비, 박스도 완성됐어! 내가 코딩한 게 진짜 작동하는지 어떻게 알 수 있어?\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- LED를 깜빡이게 해보면 돼요! 불이 켜지면 앱과 메인보드가 정상 연결된 거예요!\"}\n      ],\n      \"goals\": [\n        \"LED를 메인보드에 연결\",\n        \"코딩으로 LED 켜기 (HIGH)\",\n        \"1초 대기 후 끄기 (LOW)\",\n        \"LED 1번 깜빡이면 테스트 성공!\"\n      ],\n      \"sampleCode\": \"# 2차시 미션1: LED 점등 테스트\\nled_on(1, 1.0)   # LED 1번 켜기\\ntime.sleep(1)    # 1초 기다리기\\nled_off(1)       # LED 1번 끄기\"\n    },\n    {\n      \"id\": 2,\n      \"title\": \"LED 켜고 끄기 이해\",\n      \"tag\": \"LED\",\n      \"hardware\": \"LED 1개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"HIGH가 켜기고 LOW가 끄기라고?\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 맞아요! 전기를 보내면 켜지고(HIGH), 끊으면 꺼져요(LOW). 마치 스위치처럼요!\"}\n      ],\n      \"goals\": [\n        \"HIGH = 켜기, LOW = 끄기 개념 이해\",\n        \"LED를 3번 천천히 깜빡이기\",\n        \"대기 시간을 바꿔가며 속도 차이 느끼기\"\n      ],\n      \"sampleCode\": \"# LED 3번 깜빡이기\\nfor i in range(3):\\n    led_on(1, 1.0)\\n    time.sleep(1)\\n    led_off(1)\\n    time.sleep(1)\"\n    },\n    {\n      \"id\": 3,\n      \"title\": \"1초 기다리기 활용\",\n      \"tag\": \"LED\",\n      \"hardware\": \"LED 1개\",\n      \"story\": [\n        {\"speaker\": \"albi\", \"text\": \"삐릿! 기다리기 블록의 숫자를 바꾸면 속도가 달라져요!\"},\n        {\"speaker\": \"ares\", \"text\": \"오, 0.5초로 바꾸면 더 빠르게 깜빡이겠구나?\"}\n      ],\n      \"goals\": [\n        \"time.sleep()으로 대기 시간 조절\",\n        \"0.5초, 1초, 2초 각각 테스트\",\n        \"시간 지연의 중요성 이해\"\n      ],\n      \"sampleCode\": \"# 대기 시간 비교\\nled_on(1, 1.0)\\ntime.sleep(2.0)  # 2초 켜두기\\nled_off(1)\\ntime.sleep(0.5)  # 0.5초 끄기\"\n    },\n    {\n      \"id\": 4,\n      \"title\": \"알비 탄생! 메인보드 박스 완성\",\n      \"tag\": \"LED\",\n      \"hardware\": \"LED 1개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비, 네 몸체가 될 박스를 내가 직접 만들어줄게!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 고마워요! 제 몸이 될 박스를 정성껏 만들어주세요. 다 만들면 LED로 테스트해봐요!\"}\n      ],\n      \"goals\": [\n        \"메인보드 박스 설계도대로 제작·조립\",\n        \"LED 연결 후 켜기/끄기로 완성 확인\",\n        \"나만의 알비에게 이름 붙여주기\"\n      ],\n      \"sampleCode\": \"# 박스 완성 기념 LED 점등!\\nled_on(1, 1.0)\\ntime.sleep(0.3)\\nled_off(1)\\ntime.sleep(0.1)\\nled_on(1, 1.0)\\ntime.sleep(0.3)\\nled_off(1)\\nprint(\\\"알비 탄생!\\\")\"\n    }\n  ],\n  \"summary\": {\n    \"type\": \"keypoint\",\n    \"title\": \"핵심 포인트\",\n    \"text\": \"LED 제어의 두 축은 디지털 출력(켜기/끄기)과 시간 지연이다. time.sleep()의 인자만 바꾸어도 동일한 코드 구조에서 전혀 다른 시각적 결과가 나오므로, 학습자가 매개변수와 결과의 관계를 직관적으로 체득하기 좋다.\"\n  }\n}\n";
  DATA['Lesson03/lesson.json'] = "{\n  \"lessonNumber\": 3,\n  \"title\": \"LED 2개로 표정 만들기\",\n  \"tag\": \"WINK\",\n  \"hardware\": \"LED 2개\",\n  \"concept\": \"다채널 동시 제어, 윙크 리듬\",\n  \"intro\": \"본 차시는 LED 2개를 이용하여 알비의 '눈빛' 즉 감정 표현을 만든다. 동시 점등, 교대 점등(윙크), 빠른 깜빡임(놀람), 그리고 학습자 스스로 설계하는 감정 표현으로 이어진다. 두 개의 출력 장치를 동시에 다루는 경험을 통해, 코드가 하드웨어 여러 개를 병렬적으로 조작할 수 있다는 사고로 확장된다.\",\n  \"missions\": [\n    {\n      \"id\": 1,\n      \"title\": \"알비의 눈이 반짝!\",\n      \"tag\": \"WINK\",\n      \"hardware\": \"LED 2개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"일어나, 알비! 반짝반짝 깜빡이게 만들어볼까?\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 안녕하세요! 양쪽 눈이 동시에 깜빡이면 살아있는 것처럼 보여요!\"}\n      ],\n      \"goals\": [\n        \"LED 1번, 2번 동시에 켜기\",\n        \"1초 대기 후 동시에 끄기\",\n        \"무한 반복으로 계속 깜빡이게 구현\"\n      ],\n      \"sampleCode\": \"# 양쪽 눈 동시 깜빡이기\\nwhile True:\\n    led_on(1, 1.0)  # 왼쪽 눈\\n    led_on(2, 1.0)  # 오른쪽 눈\\n    time.sleep(1)\\n    led_off(1)\\n    led_off(2)\\n    time.sleep(1)\"\n    },\n    {\n      \"id\": 2,\n      \"title\": \"알비의 눈 번갈아 깜빡이기\",\n      \"tag\": \"WINK\",\n      \"hardware\": \"LED 2개\",\n      \"story\": [\n        {\"speaker\": \"albi\", \"text\": \"삐릿! 아레스, 이번엔 왼쪽 눈, 오른쪽 눈을 번갈아 깜빡여볼게요!\"},\n        {\"speaker\": \"ares\", \"text\": \"왼쪽 깜빡, 오른쪽 깜빡, 번갈아가면서 5번 해보자!\"}\n      ],\n      \"goals\": [\n        \"왼쪽 눈(LED1) 켜기 → 0.5초 → 끄기\",\n        \"오른쪽 눈(LED2) 켜기 → 0.5초 → 끄기\",\n        \"이 동작을 5번 반복하기\"\n      ],\n      \"sampleCode\": \"# 눈 번갈아 깜빡이기 (5회)\\nfor i in range(5):\\n    led_on(1, 1.0)   # 왼쪽 눈\\n    time.sleep(0.5)\\n    led_off(1)\\n    led_on(2, 1.0)   # 오른쪽 눈\\n    time.sleep(0.5)\\n    led_off(2)\"\n    },\n    {\n      \"id\": 3,\n      \"title\": \"알비가 깜짝 놀랐어요!\",\n      \"tag\": \"WINK\",\n      \"hardware\": \"LED 2개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! 갑자기 운석이 날아오면 어떻게 돼?\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿!! 깜짝 놀라죠! 놀라면 두 눈이 막 빠르게 깜빡이잖아요!\"}\n      ],\n      \"goals\": [\n        \"두 눈 동시에 0.1초 간격 빠른 깜빡이기\",\n        \"10번 빠르게 깜빡인 후 잠깐 멈추기\",\n        \"반복문으로 놀람 표현 완성\"\n      ],\n      \"sampleCode\": \"# 운석 경보! 빠른 깜빡임\\nwhile True:\\n    for i in range(10):\\n        led_on(1, 1.0)\\n        led_on(2, 1.0)\\n        time.sleep(0.1)\\n        led_off(1)\\n        led_off(2)\\n        time.sleep(0.1)\\n    time.sleep(0.5)  # 잠깐 멈춤\"\n    },\n    {\n      \"id\": 4,\n      \"title\": \"알비의 윙크 리듬!\",\n      \"tag\": \"WINK\",\n      \"hardware\": \"LED 2개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! 왼쪽 눈을 두 번 깜빡이고, 잠깐 쉬었다가 오른쪽 눈도 두 번 깜빡이면 어때?\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿♪ 마치 비밀 신호 같아요! 그 윙크 리듬을 5번 반복해봐요!\"}\n      ],\n      \"goals\": [\n        \"왼쪽 눈(LED1) 두 번 깜빡이기 (0.4초 간격)\",\n        \"1초 쉬기\",\n        \"오른쪽 눈(LED2) 두 번 깜빡이기\",\n        \"이 윙크 리듬을 5번 반복\"\n      ],\n      \"sampleCode\": \"# 윙크 리듬: 왼쪽 2번, 쉬고, 오른쪽 2번 (5회 반복)\\nfor i in range(5):\\n    # 왼쪽 눈 2번\\n    led_on(1, 1.0); time.sleep(0.4); led_off(1); time.sleep(0.2)\\n    led_on(1, 1.0); time.sleep(0.4); led_off(1)\\n    time.sleep(0.8)  # 쉬기\\n    # 오른쪽 눈 2번\\n    led_on(2, 1.0); time.sleep(0.4); led_off(2); time.sleep(0.2)\\n    led_on(2, 1.0); time.sleep(0.4); led_off(2)\"\n    }\n  ],\n  \"summary\": {\n    \"type\": \"notebox\",\n    \"title\": \"창작 활동\",\n    \"text\": \"미션 4는 학습자 자유 창작 미션이다. 4가지 감정 외에도 학습자가 직접 '화남'(빨갛게 빠르게), '졸림'(점점 느려짐) 등 자신만의 표현을 설계하도록 격려한다.\"\n  }\n}\n";
  DATA['Lesson04/lesson.json'] = "{\n  \"lessonNumber\": 4,\n  \"title\": \"부저로 소리 만들기\",\n  \"tag\": \"BUZZER\",\n  \"hardware\": \"부저\",\n  \"concept\": \"주파수(Hz) × 지속시간, 사이렌·SOS\",\n  \"intro\": \"본 차시는 '소리'라는 새로운 출력 모달리티를 도입한다. 학습자는 주파수(Hz)와 지속 시간(초)이라는 두 매개변수로 다양한 소리를 합성할 수 있음을 체험한다. 기본 삐빅음에서 시작해 앰뷸런스 사이렌, 운석 경보, 그리고 SOS 모스 부호까지 4단계로 발전한다.\",\n  \"missions\": [\n    {\n      \"id\": 1,\n      \"title\": \"알비, 소리 내! 부저 기초\",\n      \"tag\": \"BUZZER\",\n      \"hardware\": \"부저 1개\",\n      \"story\": [\n        {\"speaker\": \"albi\", \"text\": \"삐릿! 화성은 모래폭풍 등 다양한 위험이 있어요. 부저로 소리를 만들어봐요!\"},\n        {\"speaker\": \"ares\", \"text\": \"맞아! 위험 상황을 소리로 알릴 수 있게 경고음 시스템을 만들자!\"}\n      ],\n      \"goals\": [\n        \"부저 원리: 전기 신호 → 진동 → 소리\",\n        \"부저 켜기 → 1초 대기 → 끄기 기본 코딩\",\n        \"짧은 삐빅 소리 3번 반복\"\n      ],\n      \"sampleCode\": \"# 부저 기초 - 삐빅 3번\\nfor i in range(3):\\n    buzzer_on(500, 0.5)  # 500Hz, 0.5초\\n    time.sleep(0.3)\"\n    },\n    {\n      \"id\": 2,\n      \"title\": \"화성 앰뷸런스 사이렌!\",\n      \"tag\": \"BUZZER\",\n      \"hardware\": \"부저 1개\",\n      \"story\": [\n        {\"speaker\": \"albi\", \"text\": \"삐릿! 기지 외부에서 위험한 가스가 발견됐어요. 사이렌이 필요해요!\"},\n        {\"speaker\": \"ares\", \"text\": \"앰뷸런스처럼 삐용삐용 소리를 만들어보자! 낮은 음과 높은 음을 번갈아!\"}\n      ],\n      \"goals\": [\n        \"낮은 주파수(400Hz)로 0.5초\",\n        \"높은 주파수(800Hz)로 0.5초\",\n        \"두 음을 무한 반복 → 사이렌 완성\"\n      ],\n      \"sampleCode\": \"# 앰뷸런스 사이렌\\nwhile True:\\n    buzzer_on(400, 0.5)  # 삐─\\n    buzzer_on(800, 0.5)  # 용─\"\n    },\n    {\n      \"id\": 3,\n      \"title\": \"운석 충돌 긴급 경보!\",\n      \"tag\": \"BUZZER\",\n      \"hardware\": \"부저 1개\",\n      \"story\": [\n        {\"speaker\": \"albi\", \"text\": \"삐릿! 거대한 운석이 접근하고 있어요. 즉시 긴급 경보를 울려야 해요!\"},\n        {\"speaker\": \"ares\", \"text\": \"날카롭고 짧게 반복되는 경보음을 만들자! 긴박감 있게!\"}\n      ],\n      \"goals\": [\n        \"0.1초 켜기 → 0.1초 끄기를 10번 반복\",\n        \"잠깐 멈춤(0.5초) 후 다시 10번 반복\",\n        \"반복문으로 긴박한 연속 경보 완성\"\n      ],\n      \"sampleCode\": \"# 긴급 경보음\\nwhile True:\\n    for i in range(10):\\n        buzzer_on(1000, 0.1)\\n        time.sleep(0.1)\\n    time.sleep(0.5)\"\n    },\n    {\n      \"id\": 4,\n      \"title\": \"긴급 구조 SOS 신호!\",\n      \"tag\": \"BUZZER\",\n      \"hardware\": \"부저 1개\",\n      \"story\": [\n        {\"speaker\": \"albi\", \"text\": \"삐릿! 지구와의 주 통신이 끊겼어요. 연락할 방법을 찾아야 해요!\"},\n        {\"speaker\": \"ares\", \"text\": \"괜찮아, 모스 부호로 SOS를 보내면 돼! 짧게 3번, 길게 3번, 짧게 3번!\"}\n      ],\n      \"goals\": [\n        \"짧은 소리(0.2초) 3번: ···\",\n        \"긴 소리(0.6초) 3번: ───\",\n        \"짧은 소리(0.2초) 3번: ···\",\n        \"SOS 패턴 완성 후 반복 발신\"\n      ],\n      \"sampleCode\": \"# SOS 모스 부호\\nwhile True:\\n    # ···\\n    for i in range(3):\\n        buzzer_on(800, 0.2); time.sleep(0.1)\\n    time.sleep(0.3)\\n    # ───\\n    for i in range(3):\\n        buzzer_on(800, 0.6); time.sleep(0.1)\\n    time.sleep(0.3)\\n    # ···\\n    for i in range(3):\\n        buzzer_on(800, 0.2); time.sleep(0.1)\\n    time.sleep(1)\"\n    }\n  ],\n  \"summary\": {\n    \"type\": \"keypoint\",\n    \"title\": \"핵심 포인트\",\n    \"text\": \"부저 제어는 본질적으로 LED 제어와 동일한 구조(켜기/끄기 + 시간 지연)이지만, 주파수라는 추가 차원이 도입된다. 학습자는 단일 매개변수(밝기 또는 지연)에서 두 매개변수(주파수, 지속)로 확장된 코딩 모델을 자연스럽게 받아들이게 된다.\"\n  }\n}\n";
  DATA['Lesson05/lesson.json'] = "{\n  \"lessonNumber\": 5,\n  \"title\": \"LED 3개로 신호등 만들기\",\n  \"tag\": \"TRAFFIC\",\n  \"hardware\": \"LED 3개\",\n  \"concept\": \"시퀀스 사고, 모드 분기 (주간/야간/긴급)\",\n  \"intro\": \"본 차시는 LED 3개로 '화성 교통 신호등'을 만든다. 점등 순서를 설계하는 시퀀스 사고와, 단순한 무한 반복을 넘어선 모드 분기(주간 신호 / 야간 점멸 신호 / 화성 특별 신호)를 다룬다. 학습자는 사용자 정의 시나리오를 코드로 표현하는 첫 경험을 한다.\",\n  \"missions\": [\n    {\n      \"id\": 1,\n      \"title\": \"신호등 LED 연결 점검\",\n      \"tag\": \"TRAFFIC\",\n      \"hardware\": \"LED 3개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! 신호등 판에 LED 3개를 꽂고 각각 켜지는지 먼저 확인해봐야 해!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 맞아요! 빨강, 노랑, 초록을 각각 켜보며 정상 작동하는지 확인해봐요.\"}\n      ],\n      \"goals\": [\n        \"빨강 LED(3번) → 2초 켜기 → 끄기\",\n        \"노랑 LED(2번) → 2초 켜기 → 끄기\",\n        \"초록 LED(1번) → 2초 켜기 → 끄기\",\n        \"순서대로 점등해 정상 작동 확인\"\n      ],\n      \"sampleCode\": \"# 신호등 LED 점검\\nled_on(3, 1.0)   # 빨강\\ntime.sleep(2)\\nled_off(3)\\nled_on(2, 1.0)   # 노랑\\ntime.sleep(2)\\nled_off(2)\\nled_on(1, 1.0)   # 초록\\ntime.sleep(2)\\nled_off(1)\"\n    },\n    {\n      \"id\": 2,\n      \"title\": \"화성 교통 신호등 작동!\",\n      \"tag\": \"TRAFFIC\",\n      \"hardware\": \"LED 3개\",\n      \"story\": [\n        {\"speaker\": \"albi\", \"text\": \"삐릿! 탐사 로봇들을 안전하게 시험 주행하려면 신호등 시스템이 필요해요!\"},\n        {\"speaker\": \"ares\", \"text\": \"초록→노랑→빨강 순서로 켜지는 화성 교통 신호등을 만들어보자!\"}\n      ],\n      \"goals\": [\n        \"초록 LED 켜기 → 3초 → 끄기 (출발 신호)\",\n        \"노랑 LED 켜기 → 1초 → 끄기 (주의 신호)\",\n        \"빨강 LED 켜기 → 3초 → 끄기 (정지 신호)\",\n        \"3단계를 무한 반복하는 완전한 신호등\"\n      ],\n      \"sampleCode\": \"# 화성 신호등\\nwhile True:\\n    led_on(1, 1.0)   # 초록 출발\\n    time.sleep(3)\\n    led_off(1)\\n    led_on(2, 1.0)   # 노랑 주의\\n    time.sleep(1)\\n    led_off(2)\\n    led_on(3, 1.0)   # 빨강 정지\\n    time.sleep(3)\\n    led_off(3)\"\n    },\n    {\n      \"id\": 3,\n      \"title\": \"밤 신호등 점멸 신호\",\n      \"tag\": \"TRAFFIC\",\n      \"hardware\": \"LED 3개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비, 화성에서 밤이 되면 신호등이 달라져야 하지 않을까?\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 좋은 관찰이에요! 밤 모드로 노랑 LED만 계속 깜빡이는 점멸 신호등을 만들어봐요!\"}\n      ],\n      \"goals\": [\n        \"노랑 LED(2번)만 0.5초 간격으로 깜빡이기\",\n        \"빨강·초록은 꺼진 상태 유지\",\n        \"밤 모드 점멸 신호 무한 반복\"\n      ],\n      \"sampleCode\": \"# 밤 신호등 점멸\\nled_off(1); led_off(3)   # 빨강·초록 끄기\\nwhile True:\\n    led_on(2, 1.0)   # 노랑 켜기\\n    time.sleep(0.5)\\n    led_off(2)       # 노랑 끄기\\n    time.sleep(0.5)\"\n    },\n    {\n      \"id\": 4,\n      \"title\": \"화성 긴급 집합 신호!\",\n      \"tag\": \"TRAFFIC\",\n      \"hardware\": \"LED 3개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! 모래 폭풍이 오고 있어! 탐사 로봇들을 전부 기지로 빠르게 집합시켜야 해!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 화성 긴급 집합 신호를 보내요! 초록→노랑→빨강 3번씩 빠르게 3회 반복이에요!\"}\n      ],\n      \"goals\": [\n        \"초록 LED 0.2초 × 3번 빠르게 (집합!)\",\n        \"노랑 LED 0.2초 × 3번 빠르게 (주의!)\",\n        \"빨강 LED 0.2초 × 3번 빠르게 (위험!)\",\n        \"3색 패턴 3회 반복 → 화성 긴급 집합 신호 완성!\"\n      ],\n      \"sampleCode\": \"# 화성 긴급 집합 신호\\nfor i in range(3):       # 3회 반복\\n    for j in range(3):   # 초록 ×3\\n        led_on(1, 1.0); time.sleep(0.2); led_off(1); time.sleep(0.1)\\n    for j in range(3):   # 노랑 ×3\\n        led_on(2, 1.0); time.sleep(0.2); led_off(2); time.sleep(0.1)\\n    for j in range(3):   # 빨강 ×3\\n        led_on(3, 1.0); time.sleep(0.2); led_off(3); time.sleep(0.1)\\n    time.sleep(0.4)\"\n    }\n  ],\n  \"summary\": {\n    \"type\": \"notebox\",\n    \"title\": \"LED 색상 매핑\",\n    \"text\": \"관례: LED1=초록, LED2=노랑, LED3=빨강. 학습자가 시나리오를 코드로 표현하는 첫 경험이며, 모드 분기 사고로 확장된다.\"\n  }\n}\n";
  DATA['Lesson06/lesson.json'] = "{\n  \"lessonNumber\": 6,\n  \"title\": \"랜덤 함수와 가위바위보 게임\",\n  \"tag\": \"RANDOM\",\n  \"hardware\": \"LED 3개\",\n  \"concept\": \"random.randint, 비결정적 코드\",\n  \"intro\": \"본 차시는 '난수'라는 새로운 개념을 도입한다. 학습자는 random.randint()으로 매번 다른 결과를 만들어내는 비결정적 코드를 작성하며, 이를 게임 시나리오(가위바위보 / 3판 2선승제 / 타임어택 / 표정 변화)로 발전시킨다.\",\n  \"missions\": [\n    {\n      \"id\": 1,\n      \"title\": \"랜덤 가위바위보 시작!\",\n      \"tag\": \"RANDOM\",\n      \"hardware\": \"LED 3개\",\n      \"story\": [\n        {\"speaker\": \"albi\", \"text\": \"삐릿! 아레스, 심심한데 저와 가위바위보 게임 어때요?\"},\n        {\"speaker\": \"ares\", \"text\": \"오, 재미있을 것 같아! 그럼 알비는 LED 불빛으로, 나는 손으로 가위바위보 하는 거지?\"}\n      ],\n      \"goals\": [\n        \"LED 3개에 가위/바위/보 스티커 부착\",\n        \"랜덤으로 1~3 중 숫자 하나 선택\",\n        \"선택된 번호 LED 1개만 켜기\"\n      ],\n      \"sampleCode\": \"# 가위바위보 랜덤\\nimport random\\nchoice = random.randint(1, 3)\\nled_on(choice, 1.0)\\ntime.sleep(2)\\nled_off(choice)\"\n    },\n    {\n      \"id\": 2,\n      \"title\": \"가위바위보 하나 빼기!\",\n      \"tag\": \"RANDOM\",\n      \"hardware\": \"LED 3개\",\n      \"story\": [\n        {\"speaker\": \"albi\", \"text\": \"삐릿♪ 아레스, 하나 빼기 게임 알아요? 가위바위보, 하나 빼기~ 하면서 노는 거예요!\"},\n        {\"speaker\": \"ares\", \"text\": \"오, 재밌겠다! LED 3개가 다 켜졌다가 2개 남고, 그다음 1개만 남는 거지?\"}\n      ],\n      \"goals\": [\n        \"LED 3개 동시에 3번 깜빡임 (시작 신호)\",\n        \"one_out 블록으로 2개 랜덤 켜기\",\n        \"1.5초 후 랜덤으로 1개 끄기 → 1개만 남음!\",\n        \"'가위바위보, 하나 빼기~!' 게임 완성\"\n      ],\n      \"sampleCode\": \"# 시작 신호 (3번 깜빡)\\nfor i in range(3):\\n    led_on(1, 1.0); led_on(2, 1.0); led_on(3, 1.0)\\n    time.sleep(0.3)\\n    led_off(1); led_off(2); led_off(3)\\n    time.sleep(0.3)\\n# 하나 빼기!\\none_out()   # 랜덤 2개 켜기 → 1.5초 후 1개 끄기\"\n    },\n    {\n      \"id\": 3,\n      \"title\": \"알비를 이겨라!\",\n      \"tag\": \"RANDOM\",\n      \"hardware\": \"LED 3개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비, 이번엔 진짜 게임이야! 알비가 5번 내면, 나는 매번 이기는 손을 빠르게 내는 거야!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 도전 받아드려요! 시작 신호 3번 깜빡이고, 알비가 2초마다 랜덤으로 5번 낼게요!\"}\n      ],\n      \"goals\": [\n        \"시작 신호: LED 3개 3번 깜빡임\",\n        \"알비가 2초마다 랜덤으로 5번 손을 냄\",\n        \"아레스는 이기는 손을 빠르게 내야 해요!\",\n        \"종료 신호: LED 3개 3번 깜빡임\"\n      ],\n      \"sampleCode\": \"# 시작 신호\\nfor i in range(3):\\n    led_on(1,1); led_on(2,1); led_on(3,1)\\n    time.sleep(0.2)\\n    led_off(1); led_off(2); led_off(3)\\n    time.sleep(0.2)\\n# 알비 5번 랜덤 선택\\nfor i in range(5):\\n    random_led()\\n# 종료 신호\\nfor i in range(3):\\n    led_on(1,1); led_on(2,1); led_on(3,1)\\n    time.sleep(0.2)\\n    led_off(1); led_off(2); led_off(3)\\n    time.sleep(0.2)\"\n    },\n    {\n      \"id\": 4,\n      \"title\": \"가위바위보 왕중왕!\",\n      \"tag\": \"RANDOM\",\n      \"hardware\": \"LED 3개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비, 드디어 마지막 결전이야! 3라운드를 해서 모두 이기면 화성 가위바위보 챔피언!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿♪ 매 라운드 3번 깜빡이면 알비가 손을 낼게요! 이기는 손을 빠르게 내세요! 도전!\"}\n      ],\n      \"goals\": [\n        \"3라운드 반복 구조 완성\",\n        \"매 라운드: 가위바위보~ 신호 3번 → 알비 랜덤 선택\",\n        \"이기는 손을 빠르게 내세요!\",\n        \"마지막엔 축하 댄스: LED 5번 빠르게 깜빡\"\n      ],\n      \"sampleCode\": \"# 3라운드 가위바위보 왕중왕!\\nfor round in range(3):\\n    # 준비 신호: 가위바위보~\\n    for i in range(3):\\n        led_on(1,1); led_on(2,1); led_on(3,1)\\n        time.sleep(0.3)\\n        led_off(1); led_off(2); led_off(3)\\n        time.sleep(0.3)\\n    random_led()     # 알비의 선택\\n    time.sleep(0.3)\\n# 챔피언 축하 댄스!\\nfor i in range(5):\\n    led_on(1,1); led_on(2,1); led_on(3,1)\\n    time.sleep(0.15)\\n    led_off(1); led_off(2); led_off(3)\\n    time.sleep(0.15)\"\n    }\n  ],\n  \"summary\": {\n    \"type\": \"keypoint\",\n    \"title\": \"핵심 포인트\",\n    \"text\": \"난수는 '결정적 코드도 다른 결과를 만들 수 있다'는 점에서 학습자에게 강한 인상을 남긴다. random.randint(a,b)의 의미와, 동일 코드를 실행해도 매번 결과가 달라지는 현상을 직접 관찰하게 하는 것이 본 차시의 핵심 학습 포인트이다.\"\n  }\n}\n";
  DATA['Lesson07/lesson.json'] = "{\n  \"lessonNumber\": 7,\n  \"title\": \"DC모터 입문: 회전과 룰렛\",\n  \"tag\": \"MOTOR\",\n  \"hardware\": \"DC모터 + 원판\",\n  \"concept\": \"정/역 회전, PWM 속도 조절\",\n  \"intro\": \"본 차시는 학습자가 처음으로 운동을 코드로 제어하는 단계이다. DC모터의 회전 방향(정/역)과 PWM 기반 속도 조절을 익히고, 모터에 원판을 달아 '룰렛 게임'을 완성한다. 출력 장치가 정적인 빛/소리에서 동적인 회전으로 확장되며, 학습자는 이제 '움직이는 작품'을 만들 수 있게 된다.\",\n  \"missions\": [\n    {\n      \"id\": 1,\n      \"title\": \"DC모터 기본 회전\",\n      \"tag\": \"MOTOR\",\n      \"hardware\": \"DC모터\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! 이 모터에 전기를 공급하면 어떻게 돼?\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 코딩으로 전기를 보내면 빙글빙글 돌아요! 방향도 바꿀 수 있고 속도도 조절할 수 있어요.\"}\n      ],\n      \"goals\": [\n        \"DC모터 원리: 전기 → 자기장 → 회전 (★ 첫 등장)\",\n        \"정방향(앞)으로 3초 회전 후 정지\",\n        \"역방향(뒤)으로 3초 회전 후 정지\"\n      ],\n      \"sampleCode\": \"# DC모터 기본 회전\\n# 정방향 전진\\nmotor_forward(3)   # 3초 전진\\nmotor_stop()\\ntime.sleep(0.5)\\n# 역방향 후진\\nmotor_backward(3)  # 3초 후진\\nmotor_stop()\"\n    },\n    {\n      \"id\": 2,\n      \"title\": \"속도 조절 빠르게 느리게!\",\n      \"tag\": \"MOTOR\",\n      \"hardware\": \"DC모터\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비, DC모터로 전진·후진 속도를 조절해보자! 빠르게 갔다가 느리게 돌아오면 어떨까?\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 속도를 100%에서 50%로 바꾸면서 전진했다가 후진할 수 있어요! 두 가지 속도로 왕복해봐요!\"}\n      ],\n      \"goals\": [\n        \"전진 최고속(100%) 2초\",\n        \"전진 반속(50%) 2초\",\n        \"정지!\",\n        \"후진 최고속(100%) 2초\",\n        \"후진 반속(50%) 2초 → 최종 정지\"\n      ],\n      \"sampleCode\": \"# 전진·후진 속도 조절\\nmotor_forward(2, 100)   # 전진 2초 최고속\\nmotor_forward(2, 50)    # 전진 2초 반속\\nmotor_stop()\\nmotor_backward(2, 100)  # 후진 2초 최고속\\nmotor_backward(2, 50)   # 후진 2초 반속\\nmotor_stop()\"\n    },\n    {\n      \"id\": 3,\n      \"title\": \"차림표 원판 룰렛 돌리기!\",\n      \"tag\": \"MOTOR\",\n      \"hardware\": \"DC모터, 원판\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"이제 원판을 모터에 꽂고 화살표도 달았어! 돌리면 화살표가 어디에 멈추는지 봐야지!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 룰렛이에요! 회전하다가 멈추면 그곳이 오늘의 선택!\"}\n      ],\n      \"goals\": [\n        \"모터 최고 속도로 3초 회전 (룰렛 돌리기)\",\n        \"속도 100→70→40→0% 서서히 감속 후 정지\",\n        \"화살표가 멈추면 결과 확인\"\n      ],\n      \"sampleCode\": \"# 룰렛 돌리기\\nmotor_forward(3, 100)  # 최고 속도\\ntime.sleep(3)\\nmotor_forward(1, 70)   # 감속\\ntime.sleep(1)\\nmotor_forward(1, 40)   # 더 느리게\\nmotor_stop()\"\n    },\n    {\n      \"id\": 4,\n      \"title\": \"나만의 화성 룰렛 게임!\",\n      \"tag\": \"MOTOR\",\n      \"hardware\": \"DC모터, 원판\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! 원판 칸에 벌칙이나 상품 스티커를 붙이고 룰렛을 돌려봐! 멈추는 곳이 오늘의 미션!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿♪ 빠르게 돌다가 서서히 멈추고, 마지막엔 살짝 후진해서 딱 멈추는 진짜 룰렛이에요!\"}\n      ],\n      \"goals\": [\n        \"전진 3초 100% (룰렛 최고속 회전)\",\n        \"전진 2초 50% (서서히 감속)\",\n        \"멈춤!\",\n        \"후진 1초 50% (미세 조정 → 정확히 멈춤)\"\n      ],\n      \"sampleCode\": \"# 나만의 룰렛 게임\\nmotor_forward(3, 100)   # 전진 3초 최고속\\nmotor_forward(2, 50)    # 전진 2초 반속 감속\\nmotor_stop()             # 멈춤\\nmotor_backward(1, 50)   # 후진 1초 반속 (미세 조정)\\nmotor_stop()             # 최종 정지\"\n    }\n  ],\n  \"summary\": {\n    \"type\": \"caution\",\n    \"title\": \"주의\",\n    \"text\": \"DC모터는 큰 전류를 소모하므로 USB 전원만으로는 부족할 수 있다. 별도 배터리 팩 사용을 권장하며, 모터 정지 시에는 반드시 motor_stop()을 호출해 전류 차단을 명시할 것.\"\n  }\n}\n";
  DATA['Lesson08/lesson.json'] = "{\n  \"lessonNumber\": 8,\n  \"title\": \"알비 카트 주행\",\n  \"tag\": \"MOTOR\",\n  \"hardware\": \"DC모터 + 바퀴 2개\",\n  \"concept\": \"전·후진 주행, 가감속 곡선\",\n  \"intro\": \"본 차시는 7차시에서 익힌 DC모터에 바퀴를 결합하여 '움직이는 로봇'을 완성하는 단계이다. 전진/후진/속도 조절을 결합해 단순한 주행에서 왕복 주행, 부드러운 가감속, 그리고 학습자 자유 코스로 발전시킨다.\",\n  \"missions\": [\n    {\n      \"id\": 1,\n      \"title\": \"알비 카트 앞으로!\",\n      \"tag\": \"MOTOR\",\n      \"hardware\": \"DC모터, 바퀴 2개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! 바퀴를 달면 앞으로 달릴 수 있어?\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 물론이에요! DC모터가 정방향으로 돌면 바퀴가 구르면서 앞으로 나아가요!\"}\n      ],\n      \"goals\": [\n        \"DC모터 정방향으로 회전 → 전진\",\n        \"3초 전진 후 정지\",\n        \"알비 카트가 앞으로 달리는 것 확인\"\n      ],\n      \"sampleCode\": \"# 알비 카트 전진!\\nmotor_forward(3)   # 3초 전진\\nmotor_stop()\"\n    },\n    {\n      \"id\": 2,\n      \"title\": \"알비 카트 뒤로! 왕복 주행\",\n      \"tag\": \"MOTOR\",\n      \"hardware\": \"DC모터, 바퀴 2개\",\n      \"story\": [\n        {\"speaker\": \"albi\", \"text\": \"삐릿! 아레스, 이번엔 뒤로도 달려봐요! DC모터 방향을 반대로 바꾸면 후진!\"},\n        {\"speaker\": \"ares\", \"text\": \"앞으로 갔다가 뒤로 오면 왕복 주행이 되겠네! 해보자!\"}\n      ],\n      \"goals\": [\n        \"DC모터 역방향 회전 → 후진\",\n        \"전진(3초) → 정지(1초) → 후진(3초) → 정지\",\n        \"왕복 주행 완성\"\n      ],\n      \"sampleCode\": \"# 왕복 주행\\nmotor_forward(3)    # 전진\\nmotor_stop()\\ntime.sleep(1)\\nmotor_backward(3)   # 후진\\nmotor_stop()\"\n    },\n    {\n      \"id\": 3,\n      \"title\": \"속도 조절 주행!\",\n      \"tag\": \"MOTOR\",\n      \"hardware\": \"DC모터, 바퀴 2개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비, 항상 같은 속도로만 달리면 재미없어. 천천히 출발해서 점점 빨라지다가 멈추는 건?\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 좋아요! PWM으로 속도를 조절하면 부드럽게 달릴 수 있어요!\"}\n      ],\n      \"goals\": [\n        \"느리게 출발: 30% 속도로 2초\",\n        \"중간 속도: 60% 속도로 2초\",\n        \"전속력: 100% 속도로 2초\",\n        \"서서히 감속 70→40→10→정지 부드러운 정차\"\n      ],\n      \"sampleCode\": \"# 속도 조절 주행\\nmotor_forward_pwm(30)\\ntime.sleep(2)\\nmotor_forward_pwm(60)\\ntime.sleep(2)\\nmotor_forward_pwm(100)\\ntime.sleep(2)\\nmotor_forward_pwm(70); time.sleep(0.5)\\nmotor_forward_pwm(40); time.sleep(0.5)\\nmotor_forward_pwm(10); time.sleep(0.5)\\nmotor_stop()\"\n    },\n    {\n      \"id\": 4,\n      \"title\": \"알비 카트 나만의 코스!\",\n      \"tag\": \"MOTOR\",\n      \"hardware\": \"DC모터, 바퀴 2개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! 전진, 후진, 속도 조절 다 알았으니 나만의 주행 코스를 만들어볼게!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿♪ 전진했다가 멈추고 후진하는 나만의 드라이브 코스를 코딩해봐요!\"}\n      ],\n      \"goals\": [\n        \"전진(2초) → 정지(0.5초) → 후진(2초) → 정지 반복\",\n        \"속도 변화로 역동적 주행 연출\",\n        \"나만의 알비 카트 코스 완성 + 시연\"\n      ],\n      \"sampleCode\": \"# 나만의 주행 코스\\nfor i in range(3):\\n    motor_forward(2)\\n    motor_stop()\\n    time.sleep(0.5)\\n    motor_backward(2)\\n    motor_stop()\\n    time.sleep(0.5)\"\n    }\n  ],\n  \"summary\": {\n    \"type\": \"summary\",\n    \"title\": \"8차시 요약\",\n    \"text\": \"7차시에서 익힌 모터 제어가 '바퀴'라는 기계 부품과 만나면서 비로소 '로봇 주행'이라는 통합 시스템이 완성된다. 학습자는 PWM 듀티 사이클의 연속적 변화가 카트의 가속/감속 곡선으로 그대로 매핑됨을 체험적으로 이해한다.\"\n  }\n}\n";
  DATA['Lesson09/lesson.json'] = "{\n  \"lessonNumber\": 9,\n  \"title\": \"발사대 제작과 1분기 회고\",\n  \"tag\": \"theory\",\n  \"hardware\": \"(제작/이론)\",\n  \"concept\": \"1분기 총정리, 2분기 예고\",\n  \"intro\": \"본 차시는 코딩 없이 '손으로 만드는' 시간이다. 다음 차시부터 시작될 로켓 발사 시스템의 무대인 발사대 건물을 학습자가 직접 조립·점검하고, 1분기에서 배운 부품과 개념을 총정리한다. 4개 미션 모두 이론/제작 중심이며 본격 코딩은 다음 차시로 이어진다.\",\n  \"missions\": [\n    {\n      \"id\": 1,\n      \"title\": \"발사대 건물 조립 시작!\",\n      \"tag\": \"theory\",\n      \"hardware\": \"(제작 활동)\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! 드디어 발사대를 만들 날이야! 이 발사대에 LED와 부저를 달면 진짜 로켓 발사 시스템이 완성돼!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿♪ 설계도대로 꼼꼼하게 만들어봐요! 다음 수업에서 멋진 발사 시스템을 달아드릴게요!\"}\n      ],\n      \"goals\": [\n        \"발사대 건물 설계도대로 제작\",\n        \"부품 목록 확인 및 준비\",\n        \"뼈대 구조 먼저 조립하기\"\n      ],\n      \"sampleCode\": \"# 9차시: 발사대 건물 제작\\n# 이번 시간은 제작 미션입니다.\\n# 코딩 없이 손으로 발사대를 만들어요!\"\n    },\n    {\n      \"id\": 2,\n      \"title\": \"발사대 완성 및 점검\",\n      \"tag\": \"theory\",\n      \"hardware\": \"(제작/점검)\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"발사대가 거의 완성됐어! 단단하게 고정됐는지 확인해야 해.\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 구조물이 튼튼한지 꼭 확인하세요! 다음 시간에 여기에 LED 5개를 달 거예요!\"}\n      ],\n      \"goals\": [\n        \"조립된 발사대 구조 점검\",\n        \"LED 5개를 달 위치 미리 확인\",\n        \"발사대 완성 후 사진 찍기\"\n      ],\n      \"sampleCode\": \"# 발사대 완성!\\n# 다음 시간에 LED를 달고 코딩을 시작해요.\\nprint(\\\"발사대 건물 완성!\\\")\"\n    },\n    {\n      \"id\": 3,\n      \"title\": \"발사 시스템 계획 세우기\",\n      \"tag\": \"theory\",\n      \"hardware\": \"(설계 활동)\",\n      \"story\": [\n        {\"speaker\": \"albi\", \"text\": \"삐릿! 다음 시간에 만들 발사 시스템을 미리 계획해볼까요?\"}\n      ],\n      \"goals\": [\n        \"LED 5개 순차 점등 계획\",\n        \"카운트다운 흐름 설계\",\n        \"LED + 부저 + 모터 통합 시나리오 작성\"\n      ],\n      \"sampleCode\": \"# 10~12차시 계획\\n# LED 5개: 순차 점등 → 카운트다운\\n# 부저: 사이렌 + 멜로디\\n# DC모터: 발사 장치 작동\"\n    },\n    {\n      \"id\": 4,\n      \"title\": \"1~2분기 연결 이해하기\",\n      \"tag\": \"theory\",\n      \"hardware\": \"(이론/회고)\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! 1분기에서 배운 것들을 정리해볼까?\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿♪ LED, 부저, DC모터를 모두 배웠어요! 이것들을 합치면 진짜 로켓 발사 시스템이 완성돼요!\"}\n      ],\n      \"goals\": [\n        \"1분기 부품 총복습: LED, 부저, DC모터\",\n        \"순차·반복·시간지연·디지털출력·PWM 정리\",\n        \"2분기 예고: 서보모터, 초음파 센서, LCD\"\n      ],\n      \"sampleCode\": \"# 1분기 총정리\\nprint(\\\"배운 부품: LED, 부저, DC모터\\\")\\nprint(\\\"배운 개념: 순차, 반복, 시간지연, PWM\\\")\"\n    }\n  ],\n  \"summary\": {\n    \"type\": \"notebox\",\n    \"title\": \"교사용 메모\",\n    \"text\": \"9차시는 인지 부하가 낮은 '숨 고르기' 차시이다. 학습자가 손으로 제작 활동을 하면서 1분기 학습 내용을 체화하고, 10~12차시의 통합 프로젝트(로켓 발사 시스템)에 대한 동기를 부여하는 데 초점을 둔다.\"\n  }\n}\n";
  DATA['Lesson10/lesson.json'] = "{\n  \"lessonNumber\": 10,\n  \"title\": \"LED 5개 시퀀스와 카운트다운\",\n  \"tag\": \"SEQUENCE\",\n  \"hardware\": \"LED 5개\",\n  \"concept\": \"발사 준비/카운트다운/파티, 모듈화 사고\",\n  \"intro\": \"본 차시는 LED를 5개로 확장하여 발사 시퀀스를 구현한다. 순차 점등, 파티 조명, 카운트다운(역순 소등), 그리고 이들을 통합한 조명쇼로 이어진다. 이 차시부터 학습자는 '하나의 시나리오를 코드 블록의 조합으로 구성한다'는 통합적 사고를 시작한다.\",\n  \"missions\": [\n    {\n      \"id\": 1,\n      \"title\": \"발사 준비 순차 점등!\",\n      \"tag\": \"SEQUENCE\",\n      \"hardware\": \"LED 5개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! 발사 전에 LED가 하나씩 순서대로 켜지는 발사 준비 표시를 만들어보자!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 좋아요! 1번부터 5번까지 순서대로 켜지면 발사 준비 단계가 완료되는 거예요!\"}\n      ],\n      \"goals\": [\n        \"LED1→LED2→LED3→LED4→LED5 순서대로 0.5초 간격 켜기\",\n        \"5개 모두 켜진 후 3번 동시 깜빡임\",\n        \"순차 점등으로 발사 준비 카운트다운 완성\"\n      ],\n      \"sampleCode\": \"# 발사 준비 순차 점등\\nfor i in range(1, 6):\\n    led_on(i, 1.0)\\n    time.sleep(0.5)\\n# 준비 완료 신호\\nfor j in range(3):\\n    for i in range(1,6): led_off(i)\\n    time.sleep(0.3)\\n    for i in range(1,6): led_on(i,1.0)\\n    time.sleep(0.3)\"\n    },\n    {\n      \"id\": 2,\n      \"title\": \"발사 파티 조명!\",\n      \"tag\": \"SEQUENCE\",\n      \"hardware\": \"LED 5개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"발사 성공 후에는 파티 조명을 켜야지! LED 5개가 신나게 깜빡이는 파티 분위기!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿♪ 야호! 발사 성공 파티예요! 화려하게 깜빡이는 파티 조명을 만들어봐요!\"}\n      ],\n      \"goals\": [\n        \"5개 LED 동시에 빠르게 10번 깜빡이기\",\n        \"파도처럼 흐르는 패턴 (1→2→3→4→5→4→3→2→1)\",\n        \"세 가지 패턴 조합한 파티 조명 완성\"\n      ],\n      \"sampleCode\": \"# 파티 조명!\\nfor j in range(10):\\n    for i in range(1,6): led_on(i,1.0)\\n    time.sleep(0.2)\\n    for i in range(1,6): led_off(i)\\n    time.sleep(0.2)\\n# 파도 패턴\\nfor rep in range(3):\\n    for i in range(1,6):\\n        led_on(i,1.0); time.sleep(0.15); led_off(i)\"\n    },\n    {\n      \"id\": 3,\n      \"title\": \"LED 카운트다운 5→1!\",\n      \"tag\": \"SEQUENCE\",\n      \"hardware\": \"LED 5개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! LED 5개로 숫자 카운트다운을 표현할 수 있어? 5개가 켜진 상태에서 하나씩 꺼지면 5·4·3·2·1이 되잖아!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 오, 천재적인 아이디어예요! LED가 하나씩 꺼지면서 발사 카운트다운을 표현하는 거군요!\"}\n      ],\n      \"goals\": [\n        \"LED 5개 모두 켜기\",\n        \"1초마다 하나씩 끄기 (5→4→3→2→1→모두 꺼짐)\",\n        \"모두 꺼진 순간 전체 3번 빠르게 깜빡임 (발사!)\"\n      ],\n      \"sampleCode\": \"# 카운트다운 소등\\nfor i in range(1,6): led_on(i,1.0)\\nfor i in range(5, 0, -1):\\n    led_off(i)\\n    time.sleep(1)\\n# 발사!\\nfor j in range(3):\\n    for i in range(1,6): led_on(i,1.0)\\n    time.sleep(0.2)\\n    for i in range(1,6): led_off(i)\\n    time.sleep(0.2)\"\n    },\n    {\n      \"id\": 4,\n      \"title\": \"나만의 발사 조명쇼!\",\n      \"tag\": \"SEQUENCE\",\n      \"hardware\": \"LED 5개\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비, 지금까지 만든 것들을 합쳐서 완전한 발사 조명쇼를 만들어보자!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿♪ 순차 점등 → 카운트다운 → 발사 → 파티 순서로 하나의 이야기처럼 연결!\"}\n      ],\n      \"goals\": [\n        \"순차 점등(발사 준비) → 카운트다운(5→1)\",\n        \"발사 깜빡임 → 파티 조명\",\n        \"전체 흐름이 하나로 이어지는 조명쇼\"\n      ],\n      \"sampleCode\": \"# 통합 발사 조명쇼\\n# 1. 발사 준비\\nfor i in range(1,6): led_on(i,1.0); time.sleep(0.3)\\n# 2. 카운트다운\\nfor i in range(5,0,-1): led_off(i); time.sleep(1)\\n# 3. 발사!\\nfor j in range(5):\\n    for i in range(1,6): led_on(i,1.0)\\n    time.sleep(0.15)\\n    for i in range(1,6): led_off(i)\\n    time.sleep(0.15)\\n# 4. 파티!\\nfor rep in range(3):\\n    for i in range(1,6): led_on(i,1.0); time.sleep(0.1); led_off(i)\"\n    }\n  ],\n  \"summary\": {\n    \"type\": \"keypoint\",\n    \"title\": \"핵심 포인트\",\n    \"text\": \"미션 4는 '서브시퀀스의 합성'을 명시적으로 가르치는 첫 미션이다. 앞선 3개 미션의 코드 패턴을 그대로 '복사 + 이어붙이기'하면 통합 조명쇼가 완성된다는 점을 강조하여, 학습자가 모듈화 사고에 한 발 내디딜 수 있게 한다.\"\n  }\n}\n";
  DATA['Lesson11/lesson.json'] = "{\n  \"lessonNumber\": 11,\n  \"title\": \"LED와 부저 동기화\",\n  \"tag\": \"SYNC\",\n  \"hardware\": \"LED 5개 + 부저\",\n  \"concept\": \"빛/소리 동기, 음계(도레미파솔)\",\n  \"intro\": \"본 차시는 빛과 소리 두 출력 채널을 '동시에' 제어하여 더 풍부한 표현을 만든다. 단순 동기 깜빡임에서 시작해, 점점 빨라지는 카운트다운 부저음, 축하 멜로디(도레미파솔), 그리고 4단계 자유 창작 사운드트랙으로 발전한다. 이전 차시에서 따로 다루던 LED와 부저가 이제 하나의 통합된 '무대'로 결합된다.\",\n  \"missions\": [\n    {\n      \"id\": 1,\n      \"title\": \"LED + 부저 동시 제어!\",\n      \"tag\": \"SYNC\",\n      \"hardware\": \"LED 5개, 부저\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비, 빛이랑 소리를 동시에 낼 수 있어? 신호등이 깜빡이면서 동시에 소리도 나면 더 확실하잖아!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 물론이에요! LED를 켤 때 부저도 함께 켜면 빛과 소리가 동시에 나요!\"}\n      ],\n      \"goals\": [\n        \"LED 켜기 + 부저 켜기 동시 실행\",\n        \"0.5초 대기 후 LED 끄기 + 부저 끄기 동시에\",\n        \"빛과 소리가 완벽하게 동기화된 깜빡임 확인\"\n      ],\n      \"sampleCode\": \"# LED + 부저 동기화\\nfor i in range(5):\\n    led_on(1, 1.0)\\n    buzzer_on(500, 0.5)\\n    time.sleep(0.5)\\n    led_off(1)\"\n    },\n    {\n      \"id\": 2,\n      \"title\": \"카운트다운 발사 시스템!\",\n      \"tag\": \"SYNC\",\n      \"hardware\": \"LED 5개, 부저\",\n      \"story\": [\n        {\"speaker\": \"albi\", \"text\": \"삐릿! 카운트다운 소리를 만들어보는 건 어떨까요?\"},\n        {\"speaker\": \"ares\", \"text\": \"좋아! 삐빅 소리가 점점 빨라지면서 출발! 우주 발사 현장을 만들어보자!\"}\n      ],\n      \"goals\": [\n        \"LED 하나씩 꺼지며 카운트다운 (5→1)\",\n        \"각 숫자마다 부저 경고음 함께 출력\",\n        \"카운트다운이 진행될수록 소리가 점점 빨라짐\",\n        \"0이 되는 순간 LED 전체 깜빡 + 발사음\"\n      ],\n      \"sampleCode\": \"# 카운트다운 발사!\\nfor i in range(1,6): led_on(i,1.0)\\nfreqs = [400,500,600,700,800]\\nfor step in range(5):\\n    led_off(5-step)\\n    buzzer_on(freqs[step], 0.3)\\n    time.sleep(0.7)\\n# 발사!\\nbuzzer_on(1200, 1.0)\\nfor j in range(5):\\n    for i in range(1,6): led_on(i,1.0)\\n    time.sleep(0.15)\\n    for i in range(1,6): led_off(i)\\n    time.sleep(0.15)\"\n    },\n    {\n      \"id\": 3,\n      \"title\": \"발사 성공 세레머니!\",\n      \"tag\": \"SYNC\",\n      \"hardware\": \"LED 5개, 부저\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"발사 성공이야!! 알비! 축하 파티를 열어야 해!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿♪♪ 야호!! LED 파티 조명에 부저 축하 멜로디까지! 최고의 세레머니를 만들어봐요!\"}\n      ],\n      \"goals\": [\n        \"LED 5개 신나는 파티 패턴 깜빡이기\",\n        \"부저로 축하 멜로디 연주 (도레미파솔)\",\n        \"LED 파티 조명과 부저 멜로디가 어우러지는 세레머니\"\n      ],\n      \"sampleCode\": \"# 발사 성공 세레머니!\\n# 파티 조명\\nfor j in range(8):\\n    for i in range(1,6): led_on(i,1.0)\\n    time.sleep(0.15)\\n    for i in range(1,6): led_off(i)\\n    time.sleep(0.15)\\n# 축하 멜로디 도레미파솔\\nnotes = [262,294,330,349,392]\\nfor n in notes:\\n    buzzer_on(n, 0.3); time.sleep(0.1)\"\n    },\n    {\n      \"id\": 4,\n      \"title\": \"나만의 발사 사운드트랙!\",\n      \"tag\": \"SYNC\",\n      \"hardware\": \"LED 5개, 부저\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비, 지금까지 만든 것들로 완전한 발사 사운드트랙을 만들어보자!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿♪ 준비 → 카운트다운 → 발사 → 축하 순서로 LED와 부저를 함께 사용!\"}\n      ],\n      \"goals\": [\n        \"발사 준비: 낮은 음 + LED 순차 점등\",\n        \"카운트다운: LED 하나씩 꺼짐 + 부저 점점 빨라짐\",\n        \"발사!: LED 전체 깜빡 + 강한 발사음\",\n        \"축하: LED 파티 + 부저 멜로디\"\n      ],\n      \"sampleCode\": \"# 나만의 발사 사운드트랙\\nprint(\\\"STEP1: 발사 준비\\\")\\nfor i in range(1,6): led_on(i,1.0); buzzer_on(300,0.2); time.sleep(0.3)\\nprint(\\\"STEP2: 카운트다운\\\")\\nfor i in range(5,0,-1): led_off(i); buzzer_on(400+i*80,0.3); time.sleep(0.7)\\nprint(\\\"STEP3: 발사!!!\\\")\\nbuzzer_on(1200,1.0)\\nfor j in range(6): pass  # LED 전체 깜빡 패턴 자유 작성\\nprint(\\\"STEP4: 축하!\\\")\"\n    }\n  ],\n  \"summary\": {\n    \"type\": \"notebox\",\n    \"title\": \"음악 + 시각\",\n    \"text\": \"도레미파솔(262, 294, 330, 349, 392Hz)의 주파수는 실제 음악의 C4 옥타브에 해당한다. 학습자는 '코드로 음악을 만든다'는 새로운 표현 방식을 체험하며, 부저가 단순 경보가 아니라 작곡의 도구가 될 수 있음을 발견한다.\"\n  }\n}\n";
  DATA['Lesson12/lesson.json'] = "{\n  \"lessonNumber\": 12,\n  \"title\": \"화성 로켓 최종 발사!\",\n  \"tag\": \"LAUNCH\",\n  \"hardware\": \"LED 5개 + 부저 + DC모터\",\n  \"concept\": \"통합 시나리오, 자유 창작 발표\",\n  \"intro\": \"본 차시는 1분기 12차시 여정의 대단원이다. 모든 부품(LED 5개, 부저, DC모터)을 한 코드 안에서 통합 제어하여 '화성 로켓 발사'라는 완성된 시나리오를 구현한다. 시스템 점검 → 카운트다운 → 실제 발사 → 자유 창작 발표로 이어지며, 마지막 미션 4에서는 학습자가 1분기에 익힌 모든 도구를 자유롭게 조합해 자기만의 작품을 발표한다.\",\n  \"missions\": [\n    {\n      \"id\": 1,\n      \"title\": \"발사 전 최종 점검!\",\n      \"tag\": \"LAUNCH\",\n      \"hardware\": \"LED 5개, 부저, DC모터\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! 발사 전에 모든 시스템이 정상인지 최종 점검해야 해. LED, 부저, 모터 전부 확인하자!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿- 실제 우주선도 발사 전에 꼭 시스템 점검을 해요! 순서대로 각 장치를 확인하는 점검 코드를 만들어봐요!\"}\n      ],\n      \"goals\": [\n        \"LED 5개 순서대로 켜고 끄며 점등 확인\",\n        \"부저로 테스트 음 짧게 출력\",\n        \"DC모터 1초 짧게 회전 후 정지\",\n        \"모든 점검 완료 시 LED 전체 3번 깜빡 (점검 완료)\"\n      ],\n      \"sampleCode\": \"# 최종 점검 시스템\\nprint(\\\"=== 시스템 점검 시작 ===\\\")\\nfor i in range(1,6):\\n    led_on(i,1.0); time.sleep(0.3); led_off(i)\\nprint(\\\"LED OK\\\")\\nbuzzer_on(500, 0.3)\\nprint(\\\"부저 OK\\\")\\nmotor_forward(1); motor_stop()\\nprint(\\\"모터 OK\\\")\\n# 점검 완료 신호\\nfor j in range(3):\\n    for i in range(1,6): led_on(i,1.0)\\n    time.sleep(0.3)\\n    for i in range(1,6): led_off(i)\\n    time.sleep(0.3)\\nprint(\\\"=== 모든 시스템 정상 ===\\\")\\nprint(\\\"발사 준비 완료!\\\")\"\n    },\n    {\n      \"id\": 2,\n      \"title\": \"로켓 발사 카운트다운!\",\n      \"tag\": \"LAUNCH\",\n      \"hardware\": \"LED 5개, 부저\",\n      \"story\": [\n        {\"speaker\": \"albi\", \"text\": \"삐릿! 발사 시퀀스 프로그래밍은 정확한 순서와 타이밍이에요!\"},\n        {\"speaker\": \"ares\", \"text\": \"좋아! 경고음이 울리고, 불빛이 켜지고, 마지막으로 발사! '3, 2, 1 ... 발사!'\"}\n      ],\n      \"goals\": [\n        \"경고음(부저): 삐빅-삐빅-삐빅 3번 준비 알림\",\n        \"카운트다운: LED 5개 하나씩 꺼지며 5→4→3→2→1\",\n        \"각 숫자마다 부저 음 점점 높아지며 긴장감 고조\"\n      ],\n      \"sampleCode\": \"# 로켓 발사 카운트다운\\n# 경고음 3번\\nfor i in range(3):\\n    buzzer_on(600, 0.2); time.sleep(0.3)\\n# 카운트다운 5→1\\nfor i in range(1,6): led_on(i,1.0)\\nfor step,freq in enumerate([400,500,600,700,800]):\\n    led_off(5-step)\\n    buzzer_on(freq, 0.4)\\n    time.sleep(0.6)\"\n    },\n    {\n      \"id\": 3,\n      \"title\": \"화성 로켓 발사!!!\",\n      \"tag\": \"LAUNCH\",\n      \"hardware\": \"LED 5개, 부저, DC모터\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비!! 0이 됐어! 지금이야, 발사!!!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿!!!!!!!! 발사!!!! 아레스, 우리가 해냈어요!!!\"}\n      ],\n      \"goals\": [\n        \"경고음 사이렌 울리기\",\n        \"DC모터 회전: 발사 장치 모터 작동\",\n        \"LED 5개 시퀀스: 순서대로 점등 → 전체 빠른 깜빡임\",\n        \"발사용 건: 발사 신호 출력 → 로켓 발사!\"\n      ],\n      \"sampleCode\": \"# 최종 발사 시퀀스!\\nprint(\\\"발사 사이렌!\\\")\\nbuzzer_on(400, 0.5); buzzer_on(800, 0.5)  # 사이렌\\nprint(\\\"발사 장치 작동!\\\")\\nmotor_forward(2)    # DC모터 발사 장치\\nprint(\\\"LED 점화!\\\")\\nfor i in range(1,6): led_on(i,1.0); time.sleep(0.1)\\nfor j in range(8):\\n    for i in range(1,6): led_off(i)\\n    time.sleep(0.1)\\n    for i in range(1,6): led_on(i,1.0)\\n    time.sleep(0.1)\\nprint(\\\"발사 성공!!!\\\")\"\n    },\n    {\n      \"id\": 4,\n      \"title\": \"1분기 자유 창작 발표!\",\n      \"tag\": \"LAUNCH\",\n      \"hardware\": \"LED, 부저, DC모터\",\n      \"story\": [\n        {\"speaker\": \"ares\", \"text\": \"알비! 1분기 동안 정말 많은 걸 배웠어. 이제 이걸 전부 써서 내가 원하는 걸 만들 수 있겠어!\"},\n        {\"speaker\": \"albi\", \"text\": \"삐릿♪ 맞아요! 이제 아레스는 진짜 탐험가 코더예요! 자유롭게 조합해서 나만의 시스템을 만들어봐요! ★ 화성 탐사 훈련생 칭호 수여! ★\"}\n      ],\n      \"goals\": [\n        \"LED, 부저, DC모터 중 자유롭게 선택\",\n        \"나만의 아이디어로 우주 장치 구현\",\n        \"완성한 작품 친구들 앞에서 시연 + 발표\",\n        \"어떤 기능을 왜 만들었는지 설명하기\"\n      ],\n      \"sampleCode\": \"# 나만의 1분기 자유 창작!\\n# 이 부분을 직접 채워봐요!\\n\\n# 예시 1: 경보 시스템\\nwhile True:\\n    buzzer_on(800, 0.1)\\n    led_on(1,1.0); led_on(3,1.0)\\n    time.sleep(0.1)\\n    led_off(1); led_off(3)\\n    time.sleep(0.1)\\n\\n# 예시 2: 자동 주행 로봇\\nmotor_forward(3)\\nmotor_stop()\\nmotor_backward(1)\\nmotor_stop()\"\n    }\n  ],\n  \"summary\": {\n    \"type\": \"summary\",\n    \"title\": \"1분기 12차시 총정리\",\n    \"text\": \"배운 부품: LED 1→2→3→5개, 부저, DC모터(회전/PWM/바퀴). 배운 개념: 디지털 출력, 시간 지연, 순차, 반복, PWM, 주파수, 난수, 시나리오 통합. 대표 작품: 알비 눈빛, 화성 신호등, 가위바위보 게임, 알비 카트, 로켓 발사 시스템. 12차시 미션 4의 자유 창작 발표는 학습자가 '코딩 도구의 사용자'에서 '아이디어의 작가'로 전환되는 분기점이다.\"\n  }\n}\n";
